mapper.select:
select i.real_name as student_name, u.user_name as student_no, cl.class_name, c.course_name, q.content as question_content, q.score as max_score, e.score, e.create_time from stu_evaluation e join cou_course c on e.course_id = c.id and c.del_flag = '0' left join sys_user u_tea on c.teacher_id = u_tea.user_id join eva_question q on e.question_id = q.id join stu_student_info i on e.student_id = i.user_id and i.del_flag = '0' join sys_user u on i.user_id = u.user_id left join sys_class cl on i.class_id = cl.id where e.semester_id = #{semesterId}
and c.teacher_id = #{teacherId}
and coalesce(u_tea.nick_name, c.teacher_name) = #{teacherName}
and 1=0
order by i.real_name, c.course_name, q.sort nulls last, q.id, e.create_time
